/**
 * Media Request Schemas
 * 
 * Only request validation schemas are needed here.
 * Response schemas are auto-generated by createCrudRouter.
 */

import { BASE_FOLDERS } from './media.config.js';

/**
 * Content types for image processing presets
 */
export const CONTENT_TYPES = ['product', 'category', 'banner', 'avatar', 'default'];

/**
 * Schema options for BaseController (protects system-managed fields)
 */
export const mediaSchemaOptions = {
  fieldRules: {
    url: { systemManaged: true },
    key: { systemManaged: true },
    size: { systemManaged: true },
    mimeType: { systemManaged: true },
    dimensions: { systemManaged: true },
    variants: { systemManaged: true },
    uploadedBy: { systemManaged: true },
  },
};

// Folder path pattern: must start with allowed base folder
const baseFolderPattern = `^(${BASE_FOLDERS.join('|')})(/[a-zA-Z0-9_-]+)*$`;

/**
 * Request schemas for validation
 */
export const mediaSchemas = {
  // List query params (optional filters)
  list: {
    querystring: {
      type: 'object',
      properties: {
        page: { type: 'integer', minimum: 1 },
        after: { type: 'string', description: 'Cursor for keyset pagination' },
        limit: { type: 'integer', minimum: 1, maximum: 100 },
        folder: { type: 'string', pattern: baseFolderPattern },
        baseFolder: { type: 'string', enum: BASE_FOLDERS },
        mimeType: { type: 'string' },
        contentType: { type: 'string', enum: CONTENT_TYPES },
        search: { type: 'string' },
        sort: { type: 'string' },
      },
    },
  },

  // Update (PATCH /:id)
  update: {
    body: {
      type: 'object',
      properties: {
        alt: { type: 'string', maxLength: 255 },
        title: { type: 'string', maxLength: 255 },
        description: { type: 'string', maxLength: 1000 },
        folder: { type: 'string', pattern: baseFolderPattern },
        tags: { type: 'array', items: { type: 'string', maxLength: 50 }, maxItems: 20 },
      },
      additionalProperties: false,
    },
  },

  // Folder param for folder routes
  folderParam: {
    params: {
      type: 'object',
      properties: {
        folder: { type: 'string', minLength: 1 },
      },
      required: ['folder'],
    },
  },

  // Bulk delete
  bulkDelete: {
    body: {
      type: 'object',
      properties: {
        ids: { 
          type: 'array', 
          items: { type: 'string' }, 
          minItems: 1, 
          maxItems: 100,
          description: 'Array of media IDs to delete',
        },
      },
      required: ['ids'],
      additionalProperties: false,
    },
  },

  // Move to folder
  move: {
    body: {
      type: 'object',
      properties: {
        ids: {
          type: 'array',
          items: { type: 'string' },
          minItems: 1,
          maxItems: 100,
        },
        targetFolder: {
          type: 'string',
          pattern: baseFolderPattern,
          description: 'Target folder path (e.g., products/featured)',
        },
      },
      required: ['ids', 'targetFolder'],
      additionalProperties: false,
    },
  },

  // Presigned upload
  presignedUpload: {
    body: {
      type: 'object',
      properties: {
        filename: { type: 'string', minLength: 1 },
        mimeType: { type: 'string', minLength: 1 },
        folder: { type: 'string', pattern: baseFolderPattern },
      },
      required: ['filename', 'mimeType'],
      additionalProperties: false,
    },
  },

  // Confirm presigned upload
  confirmUpload: {
    body: {
      type: 'object',
      properties: {
        key: { type: 'string', minLength: 1, description: 'S3 object key from presigned URL' },
        filename: { type: 'string', minLength: 1 },
        mimeType: { type: 'string', minLength: 1 },
        size: { type: 'integer', minimum: 1, description: 'File size in bytes' },
        folder: { type: 'string', pattern: baseFolderPattern },
        alt: { type: 'string', maxLength: 255 },
        title: { type: 'string', maxLength: 255 },
      },
      required: ['key', 'filename', 'mimeType', 'size'],
      additionalProperties: false,
    },
  },

  // Rename folder
  renameFolder: {
    params: {
      type: 'object',
      properties: {
        folder: { type: 'string', minLength: 1 },
      },
      required: ['folder'],
    },
    body: {
      type: 'object',
      properties: {
        newName: { type: 'string', minLength: 1, pattern: '^[a-zA-Z0-9_-]+$' },
      },
      required: ['newName'],
      additionalProperties: false,
    },
  },

  // Add tags
  addTags: {
    params: {
      type: 'object',
      properties: { id: { type: 'string' } },
      required: ['id'],
    },
    body: {
      type: 'object',
      properties: {
        tags: { type: 'array', items: { type: 'string', maxLength: 50 }, minItems: 1, maxItems: 20 },
      },
      required: ['tags'],
      additionalProperties: false,
    },
  },

  // Remove tags
  removeTags: {
    params: {
      type: 'object',
      properties: { id: { type: 'string' } },
      required: ['id'],
    },
    body: {
      type: 'object',
      properties: {
        tags: { type: 'array', items: { type: 'string' }, minItems: 1, maxItems: 20 },
      },
      required: ['tags'],
      additionalProperties: false,
    },
  },
};
